{"file_path":"/home/user/workspace/lib/catalog.ts","content":"import { unstable_cache } from "next/cache";
import { getAllProducts, getProductCount, type Product } from "@/lib/db";

/**
 * Cached product list tagged with "products".
 * Returns a stable reference until the cache is invalidated via revalidateTag("products").
 */
export const getCachedProducts = unstable_cache(
  async (): Promise<Product[]> => getAllProducts(),
  ["catalog-all-products"],
  { tags: ["products"] }
);

/**
 * Cached product count tagged with "products".
 */
export const getCachedProductCount = unstable_cache(
  async (): Promise<number> => getProductCount(),
  ["catalog-product-count"],
  { tags: ["products"] }
);

/**
 * Aggregate catalog stats derived from cached data.
 */
export async function getCatalogStats(): Promise<{
  total: number;
  totalInventory: number;
  inStock: number;
  outOfStock: number;
}> {
  const products = await getCachedProducts();
  return {
    total: products.length,
    totalInventory: products.reduce((sum, p) => sum + p.inventory, 0),
    inStock: products.filter((p) => p.available).length,
    outOfStock: products.filter((p) => !p.available).length,
  };
}
"}

