import { useFormStatus } from "react-dom";

/**
 * Submit button for the catalog sync form.
 * Uses useFormStatus to show a pending state while the Server Action runs.
 */
export function SyncButton() {
  const { pending } = useFormStatus();

  return (
    <button type="submit" disabled={pending} className="sync-btn">
      {pending ? (
        <>
          <span className="spinner" />
          Syncing…
        </>
      ) : (
        <>↻ Sync Latest Catalog</>
      )}
      <style>{`
        .sync-btn {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          padding: 10px 20px;
          border: none;
          border-radius: 8px;
          background: #1a1a2e;
          color: #fff;
          font-size: 14px;
          font-weight: 600;
          cursor: pointer;
          transition: background 0.15s, transform 0.1s;
        }
        .sync-btn:hover:not(:disabled) {
          background: #16213e;
        }
        .sync-btn:active:not(:disabled) {
          transform: scale(0.97);
        }
        .sync-btn:disabled {
          opacity: 0.65;
          cursor: not-allowed;
        }
        .spinner {
          display: inline-block;
          width: 14px;
          height: 14px;
          border: 2px solid rgba(255, 255, 255, 0.3);
          border-top-color: #fff;
          border-radius: 50%;
          animation: spin 0.6s linear infinite;
        }
        @keyframes spin {
          to {
            transform: rotate(360deg);
          }
        }
      `}</style>
    </button>
  );
}
"}

