{"file_path":"/home/user/workspace/app/admin/catalog/catalog-stats.tsx","content":"export function CatalogStats({
  stats,
}: {
  stats: { total: number; totalInventory: number; inStock: number; outOfStock: number };
}) {
  const inStockPct = stats.total > 0 ? Math.round((stats.inStock / stats.total) * 100) : 0;

  return (
    <div className="stats-panel">
      <StatCard label="Total Products" value={stats.total} />
      <StatCard label="In Stock" value={stats.inStock} sub={`${inStockPct}%`} />
      <StatCard label="Out of Stock" value={stats.outOfStock} />
      <StatCard label="Total Inventory" value={stats.totalInventory} />
